# Break-even: at what year does Build TCO drop below Buy TCO?
def break_even_year(build: dict, buy: dict, max_years: int = 10) -> int | None:
    """
    build, buy: dicts with 'year1_build' and 'annual_run_rate' keys
    Returns: year at which build cumulative TCO drops below buy cumulative TCO, or None
    """
    for year in range(1, max_years + 1):
        build_cumulative = build["year1_build"] + build["annual_run_rate"] * year
        buy_cumulative = buy["year1_build"] + buy["annual_run_rate"] * year
        if build_cumulative < buy_cumulative:
            return year
    return None  # Buy never becomes more expensive in the modelled window

build = {"year1_build": 285_000, "annual_run_rate": 181_000}
buy   = {"year1_build":  80_000, "annual_run_rate": 140_000}

year = break_even_year(build, buy)
if year:
    print(f"Build becomes cheaper than Buy at year {year}")
else:
    print("Buy remains cheaper throughout the modelled window")
# With these numbers: Build annual run rate (181k) > Buy annual run rate (140k)
# so Build NEVER becomes cheaper — Buy wins on TCO at every horizon
# This is the common case when the platform subscription is reasonably priced
